INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES (111,26909,'Dr. Raj Tilak','','','103.95.81.135','2025-08-29 20:43:49','2025-08-29 15:13:49','1. The compliance across the world is not more than 40 to 50%. Out of the 2 partners in AIR therapy there are substantially greater chances of missing of ICS than SABA. In the premise \"Why should (Salbutamol + ICS) not be in vogue instead if they being separate from each other as AIR in step  1 &amp; 2 of Asthma management.\"\r\n2. The track 1 of stepwise Asthma management is admittedly superior. Track 2 is yet maintained by GINA 2025 as an option is because of MART combination not being freely available across the world (Mentioned in the guide itself). The same is very much freely available in our country. In the premise why should we at all mention the details of the Track 2 to add to the complexity, and against ease of effectively managing asthma? \r\n3. It could have been said so easily if we acknowledge that you can start managing it in the beginning as stage 3 treatment. We call the patient in follow up from time to time to assess, adjust &amp; review. In the process it shall automatically fall appropriate to the level needed for its effective control. This stand can reduce lot of complexity.\r\n4. Why can\'t MDI with spacer with or without mask be choosen as the recommended priority device of use. We unnecessarily present plethora of devices &amp; make simple issue complex. For other devices we may simply write consult the expert as written in management protocol at step 4/5.\r\n\r\nAsthma is a public health problem. If we want management of asthma reach GPs &amp; common pediatrician, &amp; thereby to larger population of Asthma health care c consumers; we will have to make it simple to execute &amp; stop chasing GINA in totality. \r\n\r\nDr. Raj Tilak',0,'1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/139.0.0.0 Safari/537.36','comment',0,0);
INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES (112,27012,'Dr.Ravi Jha','','','106.220.61.167','2025-09-03 16:33:41','2025-09-03 11:03:41','It would be better for PG students if the academic programs when uploaded in website have the name of the system/case/Diagnosis mentioned. If I want to see CNS system case presentation I donât know in which video it is there.',0,'1','Mozilla/5.0 (iPad; CPU OS 16_7_11 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) CriOS/137.0.7151.107 Mobile/15E148 Safari/604.1','comment',0,0);
