INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES (197,28649,'Krishna','','','117.99.201.237','2026-01-23 22:22:24','2026-01-23 16:52:24','Demargination (The \"Shift\" Effect)\r\nThis is the most immediate cause of high WBC counts.\r\nNormal State: In a healthy body, roughly 50% of neutrophils are circulating freely, while the other 50% are \"sticking\" to the walls of blood vessels (the marginal pool).\r\nThe Trigger: Scorpion venom stimulates the sympathetic nervous system to dump adrenaline into the bloodstream.  \r\nThe Effect: Adrenaline reduces the \"stickiness\" of these marginal neutrophils, causing them to detach from the vessel walls and flood into the circulating blood. This causes the WBC count to spike within minutes to hours, even before new cells are produced by the bone marrow.The higher the WBC, the more intense the \"adrenaline storm,\" and consequently, the higher the risk of cardiac and respiratory failure.',0,'1','Mozilla/5.0 (Linux; U; Android 16; en-in; CPH2791 Build/BP2A.250605.015) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.6422.72 Mobile Safari/537.36 HeyTapBrowser/45.13.6.1','comment',0,0);
INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES (198,28649,'Dr. Satyakumar Swamy','','','49.43.219.110','2026-01-23 22:25:46','2026-01-23 16:55:46','If pt came within 4 hr , prazosin is given irrespective of symptoms! \r\nIf pt came after 4 hr , prazosin is given if pt develops symptoms!',0,'1','Mozilla/5.0 (iPhone; CPU iPhone OS 18_7 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/26.2 Mobile/15E148 Safari/604.1','comment',0,0);
