INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES (284,29857,'Dr Sanjay narula','','','49.36.144.139','2026-05-28 21:42:17','2026-05-28 16:12:17','Good evening everyone,  i am dr sanjay narula a surgeon and medicolegal consultant and partner of dr P k Kohli in KN MEDICOLEGAL SUPPORT. I am N in KN.I Quote actual cases from my vast experience of presiding over more than 700 medicolegal enquiries in 20 years.\r\nOn subject of what\'s app consultation i am reminded of a case where a patient operated for lap hysterectomy in a corporate hospital was discharged after2 days, on 3rd day patient calls surgeon that he was having some discomfort and sent a what\'s app message,doctor being busy somewhere replied to take some medicine ,pantos etc.exchange of messages continued for next 2 days when finally pt came after 3 days, she was having peritonitis, underwent laparotomy for gut injury, finally died due to sepsis. Complaint filed by patient had a bundle of print of what\'s app exchanges as prime evidence\r\nSo we must be careful specially in post operative patients and always ask patient to come back to hospital immediately',0,'1','Mozilla/5.0 (Linux; Android 10; K) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/148.0.0.0 Mobile Safari/537.36','comment',0,0);
